const firstName = $json.first_name;
const caloriesConsumed = $json.calories_consumed || 0;
const proteinConsumed = $json.protein_consumed_g || 0;
const caloricTarget = $json.caloric_target;
const proteinTarget = $json.protein_target_g;
const mealsLogged = $json.meals_logged || 0;

let message = '';
if (mealsLogged === 0) {
  const phrases = [
    `Oye ${firstName}, ¿cómo te fue hoy? No me reportaste nada y quería saber si todo está bien.`,
    `${firstName}, ¿qué tal tu día? No alcanzo a ver qué comiste hoy. Si se te complicó el plan, no pasa nada — mañana retomamos.`,
    `Hey ${firstName}, ¿cómo estuvo el día? Si comiste fuera de plan o se te fue el tiempo, está bien. Solo cuéntame cómo te fue.`
  ];
  message = phrases[Math.floor(Math.random() * phrases.length)];
} else {
  const caloriePct = Math.round((caloriesConsumed / caloricTarget) * 100);
  const proteinPct = Math.round((proteinConsumed / proteinTarget) * 100);
  let assessment = '';
  if (caloriePct >= 85 && caloriePct <= 115 && proteinPct >= 80) assessment = 'Día sólido, cumpliste la meta.';
  else if (caloriePct < 85) assessment = 'Te faltaron calorías hoy. Intenta no saltarte comidas mañana.';
  else if (caloriePct > 115) assessment = 'Hoy te pasaste un poco de calorías. No pasa nada, mañana compensamos ligeramente.';
  else if (proteinPct < 80) assessment = 'Te faltó proteína hoy. Intenta incluir más pollo, huevos o legumbres mañana.';

  message = `${firstName}, resumen del día:\n\nCalorías: *${caloriesConsumed} de ${caloricTarget} kcal* (${caloriePct}%)\nProteína: *${proteinConsumed} de ${proteinTarget}g* (${proteinPct}%)\nComidas reportadas: ${mealsLogged}\n\n${assessment} Descansa bien, mañana te mando el plan temprano.`;
}

return [{ json: { telegramId: $json.telegram_id, userId: $json.user_id, message } }];

